You are implementing Task 25: NFC Support for a loyalty card app.

**Working directory:** C:\Users\User\loyalty-app

**What to do:**

### 1. Install NFC library

```bash
cd apps/mobile && npx expo install react-native-nfc-manager
```

### 2. Create `apps/mobile/hooks/useNfc.ts`

```typescript
import { useEffect, useState } from 'react';
import NfcManager, { NfcTech, Ndef } from 'react-native-nfc-manager';

export function useNfc() {
  const [supported, setSupported] = useState(false);

  useEffect(() => {
    NfcManager.start().then(() => setSupported(true)).catch(() => setSupported(false));
    return () => { NfcManager.cancelTechnologyRequest().catch(() => {}); };
  }, []);

  async function readTag(): Promise<string | null> {
    try {
      await NfcManager.requestTechnology(NfcTech.Ndef);
      const tag = await NfcManager.getTag();
      if (tag?.ndefMessage?.[0]) {
        const payload = Ndef.text.decodePayload(new Uint8Array(tag.ndefMessage[0].payload));
        return payload;
      }
      return null;
    } catch {
      return null;
    } finally {
      NfcManager.cancelTechnologyRequest().catch(() => {});
    }
  }

  return { supported, readTag };
}
```

### 3. Create `apps/mobile/components/nfc-scanner.tsx`

A component that shows a "Tap your phone" UI for NFC scanning:

```typescript
import { View, Text, StyleSheet, ActivityIndicator } from 'react-native';

export function NfcScanner({ scanning }: { scanning: boolean }) {
  return (
    <View style={styles.container}>
      <Text style={styles.icon}>📱</Text>
      <Text style={styles.title}>NFC Scan</Text>
      <Text style={styles.subtitle}>
        {scanning ? 'Hold your phone near the NFC tag...' : 'Tap "Start NFC Scan" to begin'}
      </Text>
      {scanning && <ActivityIndicator size="large" color="#6366f1" style={styles.spinner} />}
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20 },
  icon: { fontSize: 64, marginBottom: 16 },
  title: { fontSize: 24, fontWeight: 'bold', marginBottom: 8 },
  subtitle: { fontSize: 16, color: '#6b7280', textAlign: 'center', marginBottom: 20 },
  spinner: { marginTop: 10 },
});
```

### 4. Update `apps/mobile/app/(tabs)/scan.tsx`

Read the existing scan.tsx first. Add a toggle between QR and NFC modes at the top of the screen. When NFC mode is selected:
- Show the NfcScanner component
- Add a "Start NFC Scan" button that calls `readTag()`
- Parse the NFC payload as JSON (same format as QR: `{ qr_id, secret }`)
- Call `validate-scan` Edge Function the same way as QR

The toggle should be two buttons/tabs at the top: "QR Code" | "NFC" (only show NFC tab if `useNfc().supported` is true).

### 5. Create `apps/dashboard/src/app/(dashboard)/qr-codes/nfc/page.tsx`

A simple page showing instructions for merchants on how to program NFC tags:

```typescript
export default function NfcManagementPage() {
  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">NFC Tag Management</h1>
      <div className="max-w-2xl space-y-4">
        <div className="p-4 border rounded-lg">
          <h2 className="font-semibold mb-2">How to Program NFC Tags</h2>
          <ol className="list-decimal list-inside space-y-2 text-gray-600">
            <li>Purchase NFC tags (NTAG215 or NTAG216 recommended)</li>
            <li>Download an NFC writer app on your phone (e.g., NFC Tools)</li>
            <li>Copy the QR code data from your QR codes page</li>
            <li>Write the data as an NDEF text record to the NFC tag</li>
            <li>Place the programmed tag at your checkout counter</li>
          </ol>
        </div>
        <div className="p-4 border rounded-lg bg-blue-50">
          <h2 className="font-semibold mb-2">NFC Tag Data Format</h2>
          <p className="text-gray-600 mb-2">Each NFC tag should contain a JSON text record with:</p>
          <pre className="bg-gray-900 text-green-400 p-3 rounded text-sm overflow-x-auto">
{`{
  "qr_id": "your-qr-code-id",
  "secret": "your-qr-secret-key"
}`}
          </pre>
          <p className="text-gray-500 text-sm mt-2">Use the same data as your QR codes — NFC tags work as an alternative scan method.</p>
        </div>
      </div>
    </div>
  );
}
```

### 6. Commit

```bash
git add .
git commit -m "feat: add NFC tag reading for stamp/point collection"
```

**Important:**
- Read existing files before modifying them
- The scan.tsx already uses expo-camera CameraView for QR scanning
- Keep the existing QR scanning functionality intact — just add NFC as an alternative
- Do NOT skip the commit step

