import { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';
import { CameraView, useCameraPermissions } from 'expo-camera';
import { useTranslation } from 'react-i18next';
import { supabase } from '../../lib/supabase';
import { useNfc } from '../../hooks/useNfc';
import { NfcScanner } from '../../components/nfc-scanner';

type ScanMode = 'qr' | 'nfc';

export default function ScanScreen() {
  const [permission, requestPermission] = useCameraPermissions();
  const [scanned, setScanned] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [mode, setMode] = useState<ScanMode>('qr');
  const [nfcScanning, setNfcScanning] = useState(false);
  const { t } = useTranslation();
  const { supported: nfcSupported, readTag } = useNfc();

  async function handleScanResult(data: string) {
    if (processing) return;
    setProcessing(true);

    try {
      const payload = JSON.parse(data);
      if (!payload.qr_id || !payload.secret) {
        Alert.alert(t('scan.error'), 'Invalid scan data.');
        return;
      }

      const { data: result, error } = await supabase.functions.invoke('validate-scan', {
        body: { qr_id: payload.qr_id, secret: payload.secret },
      });

      if (error) throw error;

      if (result.success) {
        const msg = result.type === 'stamp'
          ? `Stamp added! ${result.new_total}/${result.goal}`
          : `+${result.added} points! Total: ${result.new_total}`;
        Alert.alert(t('scan.success'), msg);
      } else {
        Alert.alert(t('common.error'), result.error || t('scan.error'));
      }
    } catch (e: any) {
      Alert.alert(t('common.error'), e.message || t('scan.error'));
    } finally {
      setProcessing(false);
      setTimeout(() => setScanned(false), 2000);
    }
  }

  async function handleBarCodeScanned({ data }: { data: string }) {
    if (scanned || processing) return;
    setScanned(true);

    try {
      const payload = JSON.parse(data);
      if (payload.type !== 'loyalty_scan') {
        Alert.alert(t('scan.error'), 'This is not a loyalty QR code.');
        return;
      }
    } catch {
      Alert.alert(t('scan.error'), 'Invalid QR code.');
      return;
    }

    await handleScanResult(data);
  }

  async function handleNfcScan() {
    if (nfcScanning || processing) return;
    setNfcScanning(true);

    try {
      const data = await readTag();
      if (data) {
        await handleScanResult(data);
      } else {
        Alert.alert(t('scan.error'), 'No NFC data found. Try again.');
      }
    } finally {
      setNfcScanning(false);
    }
  }

  function renderModeToggle() {
    return (
      <View style={styles.toggleContainer}>
        <TouchableOpacity
          style={[styles.toggleButton, mode === 'qr' && styles.toggleActive]}
          onPress={() => setMode('qr')}
        >
          <Text style={[styles.toggleText, mode === 'qr' && styles.toggleTextActive]}>
            QR Code
          </Text>
        </TouchableOpacity>
        {nfcSupported && (
          <TouchableOpacity
            style={[styles.toggleButton, mode === 'nfc' && styles.toggleActive]}
            onPress={() => setMode('nfc')}
          >
            <Text style={[styles.toggleText, mode === 'nfc' && styles.toggleTextActive]}>
              NFC
            </Text>
          </TouchableOpacity>
        )}
      </View>
    );
  }

  if (mode === 'nfc') {
    return (
      <View style={styles.container}>
        {renderModeToggle()}
        <NfcScanner scanning={nfcScanning} />
        <View style={styles.nfcButtonContainer}>
          <TouchableOpacity
            style={[styles.button, (nfcScanning || processing) && styles.buttonDisabled]}
            onPress={handleNfcScan}
            disabled={nfcScanning || processing}
          >
            <Text style={styles.buttonText}>
              {nfcScanning ? 'Scanning...' : 'Start NFC Scan'}
            </Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  if (!permission) return <View />;
  if (!permission.granted) {
    return (
      <View style={styles.center}>
        {renderModeToggle()}
        <Text style={styles.text}>Camera permission is required to scan QR codes</Text>
        <TouchableOpacity style={styles.button} onPress={requestPermission}>
          <Text style={styles.buttonText}>Grant Permission</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {renderModeToggle()}
      <CameraView
        style={styles.camera}
        barcodeScannerSettings={{ barcodeTypes: ['qr'] }}
        onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
      >
        <View style={styles.overlay}>
          <View style={styles.frame} />
          <Text style={styles.hint}>{processing ? t('common.loading') : t('scan.scanning')}</Text>
        </View>
      </CameraView>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  center: { flex: 1, justifyContent: 'center', alignItems: 'center', padding: 24 },
  text: { fontSize: 16, textAlign: 'center', marginBottom: 16 },
  camera: { flex: 1 },
  overlay: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  frame: { width: 250, height: 250, borderWidth: 3, borderColor: '#fff', borderRadius: 20 },
  hint: { color: '#fff', fontSize: 16, marginTop: 20, fontWeight: '600' },
  button: { backgroundColor: '#6366f1', padding: 16, borderRadius: 12 },
  buttonDisabled: { opacity: 0.6 },
  buttonText: { color: '#fff', fontSize: 16, fontWeight: '600', textAlign: 'center' },
  toggleContainer: {
    flexDirection: 'row',
    backgroundColor: '#f3f4f6',
    borderRadius: 12,
    margin: 16,
    marginBottom: 0,
    padding: 4,
  },
  toggleButton: {
    flex: 1,
    paddingVertical: 10,
    alignItems: 'center',
    borderRadius: 10,
  },
  toggleActive: {
    backgroundColor: '#6366f1',
  },
  toggleText: {
    fontSize: 15,
    fontWeight: '600',
    color: '#6b7280',
  },
  toggleTextActive: {
    color: '#fff',
  },
  nfcButtonContainer: {
    padding: 16,
    paddingBottom: 32,
  },
});
